public class Main {
    public static void main(String[] args) {
        int n = 6;
        int[] diff = new int[n + 1]; // one extra slot for the boundary

        // Add 5 to range [1, 3]
        diff[1] += 5;
        diff[4] -= 5; // one past the end of the range

        // Add 3 to range [2, 5]
        diff[2] += 3;
        diff[6] -= 3;

        int[] result = new int[n];
        result[0] = diff[0];
        for (int i = 1; i < n; i++) {
            result[i] = result[i - 1] + diff[i];
        }

        System.out.println(java.util.Arrays.toString(result));
    }
}

public class Main {
    public static void main(String[] args) {
        int n = 5;
        int[] diff = new int[n + 1];

        int[][] updates = {{0, 1, 10}, {1, 3, 20}, {2, 4, -5}};
        for (int[] u : updates) {
            int left = u[0];
            int right = u[1];
            int value = u[2];
            diff[left] += value;
            diff[right + 1] -= value;
        }

        int[] result = new int[n];
        result[0] = diff[0];
        for (int i = 1; i < n; i++) {
            result[i] = result[i - 1] + diff[i];
        }

        System.out.println(java.util.Arrays.toString(result));
    }
}

